const config = $('Configuration').first().json;
const keywords = $input.all();

// Score and filter keywords
const scored = keywords
  .map(item => {
    const k = item.json;

    // Opportunity score: high volume + low difficulty + not top 3 = good target
    const volumeScore = Math.min(k.volume / 100, 50); // Cap at 50 points
    const difficultyScore = (100 - k.difficulty) * 0.3; // Lower is better
    const positionBonus = (k.position > 10 && k.position <= 30) ? 20 : 0; // Sweet spot
    const opportunityScore = Math.round(volumeScore + difficultyScore + positionBonus);

    return {
      json: {
        source: $('Configuration').first().json.source,
        brand: $('Configuration').first().json.your_brand,
        target_word_count: $('Configuration').first().json.target_word_count,
        keyword: k.keyword,
        volume: k.volume,
        difficulty: k.difficulty,
        current_position: k.position || 'Not ranking',
        cpc: k.cpc || 0,
        estimated_traffic: Math.round(k.volume * 0.15),
        opportunity_score: opportunityScore,
        content_type: determineContentType(k.keyword)
      }
    };
  })
  .filter(item => item.json.opportunity_score > 30)
  .sort((a, b) => b.json.opportunity_score - a.json.opportunity_score)
  .slice(0, config.articles_per_run);

function determineContentType(keyword) {
  const kw = keyword.toLowerCase();
  if (kw.includes('how to') || kw.includes('guide')) return 'tutorial';
  if (kw.includes('vs') || kw.includes('versus') || kw.includes('comparison')) return 'comparison';
  if (kw.includes('best') || kw.includes('top')) return 'listicle';
  if (kw.includes('what is') || kw.includes('definition')) return 'explainer';
  if (kw.includes('review')) return 'review';
  return 'informational';
}

return scored.length > 0 ? [scored[0]] : [];

const config = $('Configuration').first().json;
const rawText = $input.first().json.content[0].text;

// Split articles by "## Article N:" header
const articleBlocks = rawText.split(/## Article \d+:\s*/i).filter(a => a.trim());

// Generate unique review ID
const review_id = `review_${Date.now()}`;
const MAX_CHARS = 40000;

// Build output with separate columns per article
const output = {
  review_id: review_id,
  status: 'pending_review',
  created_at: new Date().toISOString(),
  total_articles: articleBlocks.length,
  brand: config.your_brand,
  reviewer_email: config.reviewer_email
};

// Add each article as separate columns
articleBlocks.forEach((articleContent, index) => {
  const num = index + 1;

  // Extract keyword from first line (title)
  const lines = articleContent.trim().split('\n');
  const keyword = lines[0].replace(/^#*\s*/, '').trim();

  // Truncate content if needed
  const content = articleContent.length > MAX_CHARS 
    ? articleContent.substring(0, MAX_CHARS) + '\n\n[TRUNCATED]'
    : articleContent;

  output[`keyword_${num}`] = keyword;
  output[`article_${num}`] = content.trim();
  output[`word_count_${num}`] = articleContent.split(/\s+/).length;
});

return [{ json: output }];

