const config = $('Configuration').first().json;
const keywords = $('Filter & Score Opportunities').all();
const relatedData = $('Get Related Keywords').all();
const questionsData = $('Get Questions (PAA)').all();

// Combine all into one object
const batchData = keywords.map((kw, index) => ({
  keyword: kw.json.keyword,
  volume: kw.json.volume,
  difficulty: kw.json.difficulty,
  content_type: kw.json.content_type,
  related: relatedData[index]?.json.keywords || [],
  questions: questionsData[index]?.json.keywords || []
}));

return [{
  json: {
    keywords_batch: batchData,
    brand: config.your_brand,
    target_word_count: config.target_word_count,
    brand_voice: config.brand_voice
  }
}];

const row = $input.first().json;

const articles = [];

// Article 1
if (row.keyword_1 && row.article_1) {
  articles.push({
    keyword: row.keyword_1,
    title: row.keyword_1.charAt(0).toUpperCase() + row.keyword_1.slice(1),
    content: row.article_1,
    word_count: row.word_count_1
  });
}

// Article 2
if (row.keyword_2 && row.article_2) {
  articles.push({
    keyword: row.keyword_2,
    title: row.keyword_2.charAt(0).toUpperCase() + row.keyword_2.slice(1),
    content: row.article_2,
    word_count: row.word_count_2
  });
}

// Article 3
if (row.keyword_3 && row.article_3) {
  articles.push({
    keyword: row.keyword_3,
    title: row.keyword_3.charAt(0).toUpperCase() + row.keyword_3.slice(1),
    content: row.article_3,
    word_count: row.word_count_3
  });
}

return articles.map(a => ({ json: a }));
